import { cn } from '@/lib/tailwind/utils';

import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs';

export type HomeView = 'kanban' | 'terminal';

const homeViewTabs = [
  { label: 'Kanban', value: 'kanban', className: 'w-[83px]' },
  { label: 'Terminal', value: 'terminal', className: 'w-[100px]' },
] satisfies Array<{
  label: string;
  value: HomeView;
  className: string;
}>;

export function SessionViewTabs(props: {
  className?: string;
  onValueChange: (value: HomeView) => void;
  value: HomeView;
}) {
  return (
    <Tabs
      aria-label="Session view"
      className={props.className}
      value={props.value}
      onValueChange={(value) => {
        if (isHomeView(value)) {
          props.onValueChange(value);
        }
      }}
    >
      <TabsList className="h-9 w-[183px] overflow-hidden rounded-none border border-border bg-background p-0 text-foreground">
        {homeViewTabs.map((tab, index) => (
          <TabsTrigger
            key={tab.value}
            value={tab.value}
            className={cn(
              'h-9 shrink-0 rounded-none border-0 px-4 text-sm leading-5 font-medium data-active:bg-sidebar-primary data-active:text-sidebar-primary-foreground',
              tab.className,
              index < homeViewTabs.length - 1 && 'border-r border-border'
            )}
          >
            {tab.label}
          </TabsTrigger>
        ))}
      </TabsList>
    </Tabs>
  );
}

function isHomeView(value: unknown): value is HomeView {
  return value === 'kanban' || value === 'terminal';
}

