import { PanelLeftCloseIcon, PanelLeftOpenIcon } from 'lucide-react';

import { SidebarTrigger, useSidebar } from '@/components/ui/sidebar';
import { ThemeSwitcher } from '@/components/ui/theme-switcher';
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from '@/components/ui/tooltip';

import {
  type HomeView,
  SessionViewTabs,
} from '@/features/home/components/molecules/session-view-tabs';

export function MainTopbar(props: {
  onViewChange: (view: HomeView) => void;
  view: HomeView;
}) {
  return (
    <header className="grid h-15 shrink-0 grid-cols-[36px_minmax(183px,1fr)_36px] items-center gap-3 border-b border-border bg-sidebar px-3">
      <SidebarToggleButton />

      <SessionViewTabs
        className="justify-self-center"
        value={props.view}
        onValueChange={props.onViewChange}
      />

      <ThemeSwitcher
        iconOnly
        triggerLabel="Toggle theme"
        triggerSize="icon"
        triggerVariant="secondary"
        triggerClassName="size-9 rounded-none shadow-none"
      />
    </header>
  );
}

function SidebarToggleButton() {
  const { state } = useSidebar();
  const isCollapsed = state === 'collapsed';
  const label = isCollapsed ? 'Expand sidebars' : 'Collapse project sidebar';
  const SidebarToggleIcon = isCollapsed
    ? PanelLeftOpenIcon
    : PanelLeftCloseIcon;

  return (
    <Tooltip>
      <TooltipTrigger
        render={
          <SidebarTrigger
            variant="secondary"
            size="icon"
            className="size-9 rounded-none shadow-none"
            icon={<SidebarToggleIcon />}
            aria-label={label}
          />
        }
      />
      <TooltipContent>
        <p>{label}</p>
      </TooltipContent>
    </Tooltip>
  );
}

